-- Daily Quest definitions table (53 rows)
-- Migrated from MSSQL DAILY_QUESTS
-- C++ Reference: _DAILY_QUEST struct, CSTLMap<_DAILY_QUEST> m_DailyQuestArray
--
-- timetype: 0=repeat, 1=time, 2=single
-- killtype: 0=solo only, 1=party only, 2=any
-- replaytime: hours until quest can be replayed (0=no replay)

CREATE TABLE IF NOT EXISTS daily_quests (
    id SMALLINT NOT NULL PRIMARY KEY,
    quest_name VARCHAR(100),
    quest_id SMALLINT NOT NULL DEFAULT 0,
    time_type SMALLINT NOT NULL DEFAULT 0,
    kill_type SMALLINT NOT NULL DEFAULT 0,
    mob_id_1 INTEGER NOT NULL DEFAULT 0,
    mob_id_2 INTEGER NOT NULL DEFAULT 0,
    mob_id_3 INTEGER NOT NULL DEFAULT 0,
    mob_id_4 INTEGER NOT NULL DEFAULT 0,
    kill_count INTEGER NOT NULL DEFAULT 1,
    reward_1 INTEGER NOT NULL DEFAULT 0,
    reward_2 INTEGER NOT NULL DEFAULT 0,
    reward_3 INTEGER NOT NULL DEFAULT 0,
    reward_4 INTEGER NOT NULL DEFAULT 0,
    count_1 INTEGER NOT NULL DEFAULT 0,
    count_2 INTEGER NOT NULL DEFAULT 0,
    count_3 INTEGER NOT NULL DEFAULT 0,
    count_4 INTEGER NOT NULL DEFAULT 0,
    zone_id SMALLINT NOT NULL DEFAULT 21,
    min_level SMALLINT NOT NULL DEFAULT 0,
    max_level SMALLINT NOT NULL DEFAULT 83,
    replay_time SMALLINT NOT NULL DEFAULT 0,
    random_id SMALLINT NOT NULL DEFAULT 0
);

-- Seed all 53 daily quest definitions from MSSQL
ON CONFLICT (id) DO NOTHING;
